\x10/127.0.0.1:38211\x12\x16Hello, p2p from python\x12\x15random-key-key-random\x1a\x0f/127.0.0.1:1234&apos;message &#123; action: &quot;p2p&quot; state: 100 data &#123; type_url: &quot;type.googleapis.com/Point2PointMessage&quot; value: &quot;
\020/127.0.0.1:38211\022\026Hello, p2p from python&quot; &#125;&#125;randomKey: &quot;random-key-key-random&quot;remoteAddressKey: &quot;/127.0.0.1:1234&quot;msg_content: Hello, p2p from pythonmsg_target: /127.0.0.1:38211 在Java中使用 同样导入到喜欢的包下，修改对应的包名即可 123456789101112131415161718192021222324252627282930313233343536373839@Slf4jpublic class ProtobufSerializeDemo &#123; @Test public void serializeToFile() throws Exception &#123; Point2PointMessageOuterClass.Point2PointMessage.Builder p2pMsgBuilder = Point2PointMessageOuterClass.Point2PointMessage.newBuilder(); p2pMsgBuilder.setTargetAddressKey("/127.0.0.1:1233"); p2pMsgBuilder.setMessage("hello from java");// BytesDataOuterClass.BytesData.Builder bytesBuilder = BytesDataOuterClass.BytesData.newBuilder();// bytesBuilder.setContent(ByteString.copyFrom("bytes data from java".getBytes(StandardCharsets.UTF_8))); MessageDtoOuterClass.MessageDto.Builder messageBuilder = MessageDtoOuterClass.MessageDto.newBuilder(); messageBuilder.setAction("p2p"); messageBuilder.setState(100); messageBuilder.setData(Any.pack(p2pMsgBuilder.build()));// messageBuilder.setData(Any.pack(bytesBuilder.build())); RpcCmdOuterClass.RpcCmd.Builder builder = RpcCmdOuterClass.RpcCmd.newBuilder(); builder.setRandomKey("RANDOM_KEY_JAVA"); builder.setRemoteAddressKey("/127.0.0.1:1234"); builder.setMessage(messageBuilder.build()); builder.build().writeTo(new FileOutputStream("java_protobuf.dat")); &#125; @Test public void deserializeFromFile() throws Exception &#123; RpcCmdOuterClass.RpcCmd rpcCmd = RpcCmdOuterClass.RpcCmd.parseFrom(new FileInputStream("java_protobuf.dat")); Point2PointMessageOuterClass.Point2PointMessage p2pMsg = rpcCmd.getMessage().getData().unpack(Point2PointMessageOuterClass.Point2PointMessage.class);// BytesDataOuterClass.BytesData bytesData = rpcCmd.getMessage().getData().unpack(BytesDataOuterClass.BytesData.class); log.info("deserialize rpcCmd: 
&#123;&#125;", rpcCmd); log.info("deserialize p2pMsg: 
&#123;&#125;", p2pMsg);// log.info("deserialize bytesData: 
&#123;&#125;", bytesData); &#125;&#125; 执行结果，可以将bytes_data相关的注释取消同时注释掉p2p_msg相关的测试BytesData类型的序列化和反序列化 12345678910111213141510:22:03.118 [main] INFO com.tony.proto.ProtobufSerializeDemo - deserialize rpcCmd: message &#123; action: &quot;p2p&quot; state: 100 data &#123; type_url: &quot;type.googleapis.com/Point2PointMessage&quot; value: &quot;
\017/127.0.0.1:1233\022\017hello from java&quot; &#125;&#125;randomKey: &quot;RANDOM_KEY_JAVA&quot;remoteAddressKey: &quot;/127.0.0.1:1234&quot;10:22:03.168 [main] INFO com.tony.proto.ProtobufSerializeDemo - deserialize p2pMsg: targetAddressKey: &quot;/127.0.0.1:1233&quot;message: &quot;hello from java&quot; 然后是Java和Python之间互相序列化和反序列化 只需要修改对应的文件地址就可以进行测试 Python反序列化Java 12java_serialize_file_path = $path_to_java_serialized$deserialize_from_file(java_serialize_file_path) 执行结果，这里演示的是BytesData类型的 12345678910111213read bytes from file: b&apos;
