\x14bytes data from java\x12\x0fRANDOM_KEY_JAVA\x1a\x0f/127.0.0.1:1234&apos;message &#123; action: &quot;p2p&quot; state: 100 data &#123; type_url: &quot;type.googleapis.com/BytesData&quot; value: &quot;
\024bytes data from java&quot; &#125;&#125;randomKey: &quot;RANDOM_KEY_JAVA&quot;remoteAddressKey: &quot;/127.0.0.1:1234&quot;bytes_data: bytes data from java Java反序列化Python 123456789 @Test public void deserializeFromPythonFile() throws Exception &#123; RpcCmdOuterClass.RpcCmd rpcCmd = RpcCmdOuterClass.RpcCmd.parseFrom(new FileInputStream($path_to_python_serialize$));// Point2PointMessageOuterClass.Point2PointMessage p2pMsg = rpcCmd.getMessage().getData().unpack(Point2PointMessageOuterClass.Point2PointMessage.class); BytesDataOuterClass.BytesData bytesData = rpcCmd.getMessage().getData().unpack(BytesDataOuterClass.BytesData.class); log.info("deserialize rpcCmd: 
&#123;&#125;", rpcCmd);// log.info("deserialize p2pMsg: 
&#123;&#125;", p2pMsg); log.info("deserialize bytesData: 
&#123;&#125;", bytesData); &#125; 执行结果，同样是BytesData类型的 123456789101112131410:33:03.360 [main] INFO com.tony.proto.ProtobufSerializeDemo - deserialize rpcCmd: message &#123; action: &quot;p2p&quot; state: 100 data &#123; type_url: &quot;type.googleapis.com/BytesData&quot; value: &quot;
\035Hello, bytes data from python&quot; &#125;&#125;randomKey: &quot;random-key-key-random&quot;remoteAddressKey: &quot;/127.0.0.1:1234&quot;10:33:03.402 [main] INFO com.tony.proto.ProtobufSerializeDemo - deserialize bytesData: content: &quot;Hello, bytes data from python&quot; 在Java平台，还有个更好用的工具可以不用手写proto文件 这个工具是io.protostuff 通过maven导入依赖 12345678910111213141516&lt;dependency&gt; &lt;groupId&gt;io.protostuff&lt;/groupId&gt; &lt;artifactId&gt;protostuff-core&lt;/artifactId&gt; &lt;version&gt;1.6.0&lt;/version&gt;&lt;/dependency&gt;&lt;dependency&gt; &lt;groupId&gt;io.protostuff&lt;/groupId&gt; &lt;artifactId&gt;protostuff-runtime&lt;/artifactId&gt; &lt;version&gt;1.6.0&lt;/version&gt;&lt;/dependency&gt;&lt;!-- 用于创建对象 --&gt;&lt;dependency&gt; &lt;groupId&gt;org.objenesis&lt;/groupId&gt; &lt;artifactId&gt;objenesis&lt;/artifactId&gt; &lt;version&gt;2.2&lt;/version&gt;&lt;/dependency&gt; 创建序列化工具类 12345678910111213141516171819202122232425262728293031323334353637383940414243444546474849505152535455565758596061626364656667686970717273747576777879808182838485868788899091929394import io.protostuff.LinkedBuffer;import io.protostuff.ProtobufIOUtil;import io.protostuff.Schema;import io.protostuff.runtime.DefaultIdStrategy;import io.protostuff.runtime.RuntimeSchema;import lombok.extern.slf4j.Slf4j;import org.objenesis.Objenesis;import org.objenesis.ObjenesisStd;import java.io.ByteArrayInputStream;import java.io.ByteArrayOutputStream;import java.io.IOException;import java.io.InputStream;import java.io.OutputStream;/** * 基于Protostuff优化版的ProtobufIOUtil实现序列化，理论上可以支持跨语言序列化 * * @author jiangwenjie 2019/10/30 */@Slf4jpublic class ProtobufSerializer &#123; private final static Objenesis OBJENESIS = new ObjenesisStd(true); private ProtobufSerializer() &#123; &#125; private static class SingletonHolder &#123; final static ProtobufSerializer INSTANCE = new ProtobufSerializer(); &#125; public static ProtobufSerializer getInstance() &#123; return ProtobufSerializer.SingletonHolder.INSTANCE; &#125; public void serialize(Object obj, OutputStream outputStream) &#123; Class clz = obj.getClass(); LinkedBuffer buffer = LinkedBuffer.allocate(LinkedBuffer.DEFAULT_BUFFER_SIZE); try &#123; Schema schema = getSchema(clz); ProtobufIOUtil.writeTo(outputStream, obj, schema, buffer); &#125; catch (IOException e) &#123; log.error("序列化对象失败", e); &#125; finally &#123; buffer.clear(); &#125; &#125; public byte[] serialize(Object obj) &#123; Class clz = obj.getClass(); LinkedBuffer buffer = LinkedBuffer.allocate(LinkedBuffer.DEFAULT_BUFFER_SIZE); try (ByteArrayOutputStream arrayOutputStream = new ByteArrayOutputStream()) &#123; Schema schema = getSchema(clz); ProtobufIOUtil.writeTo(arrayOutputStream, obj, schema, buffer); return arrayOutputStream.toByteArray(); &#125; catch (IOException e) &#123; log.error("序列化对象失败", e); &#125; finally &#123; buffer.clear(); &#125; return new byte[0]; &#125; public &lt;T&gt; T deSerialize(InputStream inputStream, Class&lt;T&gt; clazz) &#123; T object = OBJENESIS.newInstance(clazz); Schema&lt;T&gt; schema = getSchema(clazz); try &#123; ProtobufIOUtil.mergeFrom(inputStream, object, schema); return object; &#125; catch (IOException e) &#123; log.error("反序列化对象失败", e); &#125; return null; &#125; public &lt;T&gt; T deSerialize(byte[] param, Class&lt;T&gt; clazz) &#123; T object = OBJENESIS.newInstance(clazz); Schema&lt;T&gt; schema = getSchema(clazz); try (ByteArrayInputStream inputStream = new ByteArrayInputStream(param)) &#123; ProtobufIOUtil.mergeFrom(inputStream, object, schema); return object; &#125; catch (IOException e) &#123; log.error("反序列化对象失败", e); &#125; return null; &#125; private &lt;T&gt; Schema&lt;T&gt; getSchema(Class&lt;T&gt; clz) &#123; return RuntimeSchema.createFrom(clz, new DefaultIdStrategy()); &#125;&#125; 创建序列化对象 123456789101112131415161718192021222324252627282930313233343536373839404142434445464748495051525354555657585960616263646566676869707172737475767778798081828384858687888990919293949596979899100101102103104105106107108109110111112import lombok.Data;import lombok.extern.slf4j.Slf4j;import java.io.Serializable;/** * @author jiangwenjie 2019/10/22 */@Data@Slf4jpublic class RpcCmd implements Serializable &#123; private MessageDto message; private String randomKey; /** * 目标地址，不需要序列化传输 */ private transient String remoteAddressKey;&#125;import com.tony.constants.EnumNettyState;import com.tony.serializer.impl.ProtobufSerializer;import lombok.Data;import lombok.EqualsAndHashCode;import lombok.ToString;import lombok.extern.slf4j.Slf4j;import java.io.Serializable;/** * 消息对象 * * @author jiangwenjie 2019/10/22 */@Slf4j@Data@ToString@EqualsAndHashCodepublic class MessageDto implements Serializable &#123; private String action; private int state = 100; /** * 跨语言使用Protostuff中提供的protobuff序列化传递复杂对象 */ private byte[] bytesData; private Serializable serialData; public &lt;T&gt; T dataOfClazz(Class&lt;T&gt; clazz, boolean isStuff) &#123; if (isStuff) &#123; return serialDataOfClazz(clazz); &#125; else &#123; return bytesDataOfClass(clazz); &#125; &#125; public &lt;T extends Serializable&gt; void setData(T object, boolean isStuff) &#123; if (isStuff) &#123; setSerialData(object); &#125; else &#123; setBytesData(object); &#125; &#125; @SuppressWarnings("unchecked") private &lt;T&gt; T serialDataOfClazz(Class&lt;T&gt; clazz) &#123; if (serialData == null) &#123; return null; &#125; if (clazz.isInstance(serialData)) &#123; return (T)serialData; &#125; else &#123; throw new IllegalArgumentException("data is not instance of class:" + clazz.getName()); &#125; &#125; private &lt;T&gt; T bytesDataOfClass(Class&lt;T&gt; clazz) &#123; if (bytesData == null) &#123; return null; &#125; try &#123; return ProtobufSerializer.getInstance().deSerialize(bytesData, clazz); &#125; catch (Exception e) &#123; log.error("反序列化data对象失败，请确认对象是否为：&#123;&#125; 类型", clazz); &#125; return null; &#125; private &lt;T extends Serializable&gt; void setBytesData(T data) &#123; this.bytesData = ProtobufSerializer.getInstance().serialize(data); &#125;&#125;import lombok.Data;import java.io.Serializable;/** * 点对点通信data对象 * * @author jiangwenjie 2019/10/26 */@Datapublic class Point2PointMessage implements Serializable &#123; private String targetAddressKey; private String message;&#125; 序列化测试123456789101112131415161718192021222324252627282930313233343536import lombok.extern.slf4j.Slf4j;import org.junit.Test;import java.io.FileInputStream;import java.io.FileOutputStream;/** * @author jiangwenjie 2019/11/1 */@Slf4jpublic class JavaProtostuffSerializeDemo &#123; @Test public void serializeToFile() throws Exception &#123; Point2PointMessage p2pMsg = new Point2PointMessage(); p2pMsg.setTargetAddressKey("/127.0.0.1:1233"); p2pMsg.setMessage("message from java"); MessageDto messageDto = new MessageDto(); messageDto.setAction("p2p"); messageDto.setState(100); messageDto.setData(p2pMsg, false); RpcCmd rpcCmd = new RpcCmd(); rpcCmd.setMessage(messageDto); rpcCmd.setRandomKey("RANDOM_KEY_JAVA"); rpcCmd.setRemoteAddressKey("/127.0.0.1:1234"); ProtobufSerializer.getInstance().serialize(rpcCmd, new FileOutputStream("java_proto_simple.dat")); &#125; @Test public void deserializeFromFile() throws Exception &#123; RpcCmd rpcCmd = ProtobufSerializer.getInstance().deSerialize(new FileInputStream("java_proto_simple.dat"), RpcCmd.class); log.info("deserialize cmd:
&#123;&#125;", rpcCmd); log.info("deserialize p2p msg:
&#123;&#125;", rpcCmd.getMessage().dataOfClazz(Point2PointMessage.class, false)); &#125;&#125; 测试输出123411:02:45.646 [main] INFO com.tony.simple.JavaProtostuffSerializeDemo - deserialize cmd:RpcCmd(message=MessageDto(action=p2p, state=100, bytesData=[10, 15, 47, 49, 50, 55, 46, 48, 46, 48, 46, 49, 58, 49, 50, 51, 51, 18, 17, 109, 101, 115, 115, 97, 103, 101, 32, 102, 114, 111, 109, 32, 106, 97, 118, 97], serialData=null, isFromBuff=false), randomKey=RANDOM_KEY_JAVA, remoteAddressKey=null)11:02:45.651 [main] INFO com.tony.simple.JavaProtostuffSerializeDemo - deserialize p2p msg:Point2PointMessage(targetAddressKey=/127.0.0.1:1233, message=message from java) MessageDto中的Data 可以泛型化使用12345/** * 跨语言使用Protostuff中提供的protobuff序列化传递复杂对象 */private byte[] bytesData;private Serializable serialData; 当序列化和反序列化不需要跨平台使用时，可以直接使用Serializable类型，反之需要用byte数组保存数据，进行二次序列化和反序列化。同时可以在序列化工具类ProtobufSerializer中将ProtobufIOUtil修改为ProtostuffIOUtil 通过setData方法进行响应的操作 1234567public &lt;T extends Serializable&gt; void setData(T object, boolean isStuff) &#123; if (isStuff) &#123; setSerialData(object); &#125; else &#123; setBytesData(object); &#125;&#125; 跨语言Python中反序列化创建proto文件 MessageDto.proto 1234567syntax = "proto3";message MessageDto &#123; string action=1; int32 state=2; bytes data=3;&#125; RpcCmd.proto 12345678syntax = "proto3";import "MessageDto.proto";message RpcCmd &#123; MessageDto message = 1; string randomKey = 2; string remoteAddressKey = 3;&#125; Point2PointMessage.proto 1234567syntax = "proto3";message Point2PointMessage &#123; bytes java_class = 127; string targetAddressKey = 1; string message = 2;&#125; BytesData.proto 1234syntax = "proto3";message BytesData &#123; bytes content=1;&#125; 导出Python3对象定义文件 此时没有用到Any类型 可以直接导出为Python3的py文件 --python3_out123456789101112131415161718192021222324252627282930313233343536373839404142434445464748495051525354555657585960616263646566- 和pb2的区别是序列化和反序列化的方法名称进行了修改 - pb2中用的是`ParseFromString`和`SerializeToString` - pb3中修改成了`encode_to_bytes`和`parse_from_bytes`##### 在Python中使用- 同样的放到喜欢的包下，修改对应包名 这里不赘述 ```python #!/usr/bin/python3 # -*-coding: utf-8 -*- from com.tony.proto.py3 import RpcCmd, Point2PointMessage, MessageDto, BytesData def serialize_to_file(file_path): p2p_msg = Point2PointMessage.Point2PointMessage() p2p_msg.message = &quot;Hello, p2p from python&quot; p2p_msg.targetAddressKey = &quot;/127.0.0.1:38211&quot; # bytes_data = BytesData.BytesData() # bytes_data.content = &quot;bytes data from python&quot; rpc_cmd = RpcCmd.RpcCmd() rpc_cmd.randomKey = &quot;random-key-key-random&quot; rpc_cmd.remoteAddressKey = &quot;/127.0.0.1:1234&quot; rpc_cmd.message.action = &quot;p2p&quot; rpc_cmd.message.state = 100 rpc_cmd.message.data = p2p_msg.encode_to_bytes() # rpc_cmd.message.data = bytes_data.encode_to_bytes() bytes_write = rpc_cmd.encode_to_bytes() fw = open(file_path, mode=&quot;wb&quot;) fw.write(bytes_write) fw.flush() fw.close() print(&quot;write bytes to file:&quot;, bytes_write) def deserialize_from_file(file_path): fo = open(file_path, mode=&quot;rb&quot;) bytes_read = fo.read() fo.close() print(&quot;read bytes from file:&quot;, bytes_read) rpc_cmd = RpcCmd.RpcCmd() rpc_cmd.parse_from_bytes(bytes_read) print(rpc_cmd) msg_bytes = rpc_cmd.message.data print(&quot;message bytes&quot;, msg_bytes) p2p_msg = data_of(rpc_cmd.message, Point2PointMessage.Point2PointMessage) # bytes_data = data_of(rpc_cmd.message, BytesData.BytesData) print(&quot;msg_content:&quot;, p2p_msg.message) print(&quot;msg_target:&quot;, p2p_msg.targetAddressKey) # print(&quot;bytes_data:&quot;, bytes_data.content) def data_of(message: RpcCmd.MessageDto, message_identify): content = message_identify() content.parse_from_bytes(message.data) return content if __name__ == &quot;__main__&quot;: serialize_file_path = &quot;./trans-data.dat&quot; serialize_to_file(serialize_file_path) deserialize_from_file(serialize_file_path) 执行结果如下，同样的可以将bytes_data相关的注释取消同时注释掉p2p_msg相关的测试BytesData类型的序列化和反序列化 123456789101112write bytes to file: b&apos;
